import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useVoiceControl } from '../context/VoiceControlContext';
import {
    Container,
    Paper,
    Button,
    Typography,
    Box,
    Alert,
    TextField
} from '@mui/material';
import HelpIcon from '@mui/icons-material/Help';
import ClearIcon from '@mui/icons-material/Clear';
import { VoiceInput } from '../components/VoiceInput';

const RegisterPage = () => {
    const navigate = useNavigate();
    const { register } = useAuth();
    const { speakFeedback } = useVoiceControl();
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        password: '',
        confirmPassword: ''
    });
    const [error, setError] = useState('');
    
    const nameRef = useRef(null);
    const emailRef = useRef(null);
    const passwordRef = useRef(null);
    const confirmPasswordRef = useRef(null);

    const speak = speakFeedback;

    const handleChange = (e) => {
        setFormData({
            ...formData,
            [e.target.name]: e.target.value
        });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        
        if (formData.password !== formData.confirmPassword) {
            setError('Passwords do not match');
            return;
        }

        try {
            await register({
                name: formData.name,
                email: formData.email,
                password: formData.password
            });
            navigate('/login');
        } catch (err) {
            setError(err.message);
        }
    };

    return (
        <Container maxWidth="sm">
            <Box sx={{ mt: 8 }}>
                <Paper elevation={3} sx={{ p: 4 }}>
                    <Typography variant="h4" component="h1" gutterBottom align="center">
                        Register
                    </Typography>
                    
                    {error && (
                        <Alert severity="error" sx={{ mb: 2 }}>
                            {error}
                        </Alert>
                    )}

                    <form onSubmit={handleSubmit}>
                        <VoiceInput
                            label="Full Name"
                            value={formData.name}
                            onChange={(value) => handleChange({ target: { name: 'name', value }})}
                        />
                        <VoiceInput
                            label="Email"
                            value={formData.email}
                            onChange={(value) => handleChange({ target: { name: 'email', value }})}
                        />
                        <VoiceInput
                            label="Password"
                            value={formData.password}
                            onChange={(value) => handleChange({ target: { name: 'password', value }})}
                            type="password"
                        />
                        <VoiceInput
                            label="Confirm Password"
                            value={formData.confirmPassword}
                            onChange={(value) => handleChange({ target: { name: 'confirmPassword', value }})}
                            type="password"
                        />
                        <Button
                            type="submit"
                            fullWidth
                            variant="contained"
                            color="primary"
                            sx={{ mt: 3, mb: 2 }}
                        >
                            Register
                        </Button>
                    </form>
                    
                    <Box sx={{ textAlign: 'center', mt: 2 }}>
                        <Typography variant="body2">
                            Already have an account?{' '}
                            <Link to="/login">Login here</Link>
                        </Typography>
                    </Box>
                </Paper>
            </Box>
        </Container>
    );
};

export default RegisterPage;
